<main id="content"><br> 
			<style>
.n-columns-2 {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  font-weight: 700;
}

.n-columns-2 a {
  text-align: center;
  margin: 3px;
}

/* === Warna hijau neon ala {{judul}} === */
.login,
.register {
  color: #eaffef;
  padding: 10px 15px;
  font-family: "Poppins", sans-serif;
  font-weight: 600;
  position: relative;
  overflow: hidden; /* untuk efek kilap */
}

/* Tombol LOGIN */
.login,
.login-button {
  text-shadow: 0 0 6px rgb(58, 193, 255);
  border-radius: 10px;
  border: 2px solid rgb(11, 237, 245);
  background: linear-gradient(180deg, #000000 0%, #4706fc 100%);
  color: #eaffef;
  transition: all 0.3s ease;
}

.login:hover {
  background: linear-gradient(180deg, #00c3ff 0%, #000000 100%);
  color: #ffffff;
  box-shadow: 0 0 14px rgb(255, 217, 0)
  transform: translateY(-2px);
}

/* Tombol DAFTAR */
.register,
.register-button {
  text-shadow: 0 0 6px rgb(4, 8, 241);
  border-radius: 10px;
  background: linear-gradient(180deg, #000000 0%, #06d7f3 100%);
  border: 2px solid rgb(7, 23, 236);
  color: #ffffff;
  transition: all 0.3s ease;
}

.register:hover {
  background: linear-gradient(180deg, #00c3ff 0%, #000000 100%);
  color: #ffffff;
  box-shadow: 0 0 14px rgb(255, 255, 255);
  transform: translateY(-2px);
}

/* === Efek kilap untuk tombol === */
.login::after,
.register::after {
  content: "";
  position: absolute;
  top: -50%;
  left: -75%;
  width: 50%;
  height: 200%;
  background: linear-gradient(
    120deg,
    rgba(255,255,255,0) 0%,
    rgba(255,255,255,0.4) 50%,
    rgba(255,255,255,0) 100%
  );
  transform: skewX(-20deg);
  transition: all 0.7s ease;
  pointer-events: none;
}

.login:hover::after,
.register:hover::after {
  left: 150%;
  transition: all 0.7s ease;
}

</style>
