<style>
    /* === FOOTER SLOT GAMING TEMA {{judul}} NEON === */
    .shura-gacor-fixed-footer {
      position: fixed;
      bottom: 0;
      left: 0;
      right: 0;
      z-index: 99;
      display: flex;
      justify-content: space-evenly;
      align-items: center;
      gap: 8px;
      padding: 12px 0;
      background: linear-gradient(180deg, #000000 0%, #000000 100%);
      border-top: 2px solid rgba(0, 0, 0, 0.5);
      box-shadow: 0 -3px 18px rgb(0, 238, 255),
                  inset 0 0 12px rgb(0, 238, 255);
      border-radius: 20px 20px 0 0;
      font-family: "Poppins", "Segoe UI", sans-serif;
      color: #eaffef;
    }
    
    /* === Tombol Footer === */
    .shura-gacor-fixed-footer a {
      flex: 1;
      max-width: 90px;
      text-align: center;
      text-decoration: none;
      color: #00c3ff;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 4px;
      font-size: 13px;
      font-weight: 600;
      text-shadow: 0 0 6px #00c3ff, 0 0 12px #00c3ff;
      transition: all 0.25s ease-in-out;
    }
    
    /* Hover efek */
    .shura-gacor-fixed-footer a:hover {
      color: #ffffff;
      transform: translateY(-6px) scale(1.1);
      text-shadow: 0 0 10px #00c3ff, 0 0 15px #00c3ff, 0 0 20px #00c3ff;
    }
    
    /* === Ikon tombol === */
    .shura-gacor-fixed-footer img {
      width: 26px;
      height: 26px;
      filter: drop-shadow(0 0 5px #00c3ff);
      transition: transform 0.3s ease, filter 0.3s ease;
    }
    
    .shura-gacor-fixed-footer a:hover img {
      transform: scale(1.25);
      filter: drop-shadow(0 0 10px #00c3ff) drop-shadow(0 0 10px #00c3ff);
    }
    
    /* === Tombol Tengah (Spesial: Daftar) === */
    .shura-gacor-fixed-footer .tada {
      background: radial-gradient(circle, rgba(255, 255, 255, 0.2) 0%, transparent 70%);
      border-radius: 50%;
      padding: 8px;
      transform: scale(1.2);
      animation: neonGlow 2.5s infinite alternate;
    }
    
    @keyframes neonGlow {
      0% {
        box-shadow: 0 0 6px #00c3ff, 0 0 12px #00c3ff;
      }
      25% {
        box-shadow: 0 0 12px #00c3ff, 0 0 20px #00c3ff;
      }
      50% {
        box-shadow: 0 0 14px #00c3ff, 0 0 25px #00c3ff;
      }
      75% {
        box-shadow: 0 0 18px #00c3ff, 0 0 30px #00c3ff;
      }
      100% {
        box-shadow: 0 0 6px #00c3ff, 0 0 12px #00c3ff;
      }
    }
    
    /* Klik efek */
    .shura-gacor-fixed-footer a:active {
      transform: scale(0.95);
      opacity: 0.85;
