<style>
/* === Snowfall Overlay === */
.snow-wrap {
  position: fixed;
  inset: 0;
  pointer-events: none;
  overflow: hidden;
  z-index: 9999;
}

.snowflake {
  position: absolute;
  top: -10vh;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, #fff 0 45%, #fff 55%, rgba(255,255,255,.6) 70%);
  filter: drop-shadow(0 0 10px #fff) blur(.3px);
  opacity: .95;
  animation:
    glow 2s ease-in-out infinite alternate,
    fall var(--dur,12s) linear var(--delay,0s) infinite,
    sway var(--sway,6s) ease-in-out var(--delay,0s) infinite alternate;
}

.snowflake.-sm { width:4px; height:4px; opacity:.8; }
.snowflake.-lg { width:12px; height:12px; opacity:.9; }

@keyframes fall {
  to { transform: translate3d(var(--drift,0),110vh,0) rotate(var(--rot,180deg)); }
}
@keyframes sway {
  from { margin-left:-10px; }
  to   { margin-left:10px; }
}
@keyframes glow {
  0%,100% { filter: drop-shadow(0 0 6px rgba(255,255,255,.8)); }
  50% { filter: drop-shadow(0 0 15px rgba(255,255,255,.7)); }
}

/* === Anime Runner === */
.anime-runner {
  position: fixed;
  bottom: 20px;
  width: 120px;
  pointer-events: none;
  z-index: 9998;
  will-change: transform;
}

.run-ltr { animation: run-ltr linear infinite; }
.run-rtl { animation: run-rtl linear infinite; transform: scaleX(-1); }

@keyframes run-ltr {
  from { left: -150px; }
  to   { left: 120vw; }
}

@keyframes run-rtl {
  from { right: -150px; }
  to   { right: 120vw; }
}

/* Reduce motion */
@media (prefers-reduced-motion: reduce) {
  .snowflake, .anime-runner { animation: none; }
}
</style>

