<img id="runner" class="anime-runner run-ltr" alt="Anime Runner" src="https://www.animatedimages.org/data/media/359/animated-santa-claus-image-0420.gif" style="animation-duration: 11.9073s;" />

<script>
(function(){
  /* === Snow Generator === */
  const wrap = document.getElementById('snow');
  const COUNT = 50;
  for(let i=0;i<COUNT;i++){
    const f = document.createElement('span');
    f.className = 'snowflake ' + (Math.random()<.2?'-lg':(Math.random()<.6?'-sm':''));
    f.style.left = Math.random()*100+'vw';
    f.style.setProperty('--delay',(Math.random()*-12)+'s');
    f.style.setProperty('--dur',(8+Math.random()*10)+'s');
    f.style.setProperty('--sway',(4+Math.random()*6)+'s');
    f.style.setProperty('--drift',(Math.random()*120-60)+'px');
    f.style.setProperty('--rot',(Math.random()*360)+'deg');
    wrap.appendChild(f);
  }

  /* === Anime Runner Logic === */
  const runner = document.getElementById('runner');

  const characters = [
    { name:'Naruto', src:'https://i.postimg.cc/WbBBQ1Lg/ae89c2b34198141f73e42583b55ad2d4.gif' },
    { name:'Sasuke', src:'https://i.pinimg.com/originals/81/8e/55/818e55f3974e7e5bbadb45f7b2df805f.gif' },
    { name:'Luffy',  src:'https://i.redd.it/svtoicizj0bb1.gif' },
    { name:'Goku',   src:'https://media2.giphy.com/media/v1.Y2lkPTZjMDliOTUydHF5cm93bWVvejc1am5mYTB1ZjJyYTRzYXRidnpnZjJqaWY1a2dmeSZlcD12MV9zdGlja2Vyc19zZWFyY2gmY3Q9cw/SaSAUwiGPsPtswfPRk/200w.gif' }
  ];

  function spawnRunner(){
    const char = characters[Math.floor(Math.random()*characters.length)];
    const dir = Math.random() > 0.5 ? 'ltr' : 'rtl';
    const speed = 8 + Math.random()*10;

    runner.src = char.src;
    runner.style.animationDuration = speed+'s';
    runner.style.left = '';
    runner.style.right = '';

    runner.className = 'anime-runner ' + (dir==='ltr'?'run-ltr':'run-rtl');
  }

  spawnRunner();
  setInterval(spawnRunner, 12000);
    })();
    </script>

